import{_ as a,c as t,o as i,ae as l}from"./chunks/framework.B7Y1jjX-.js";const u=JSON.parse('{"title":"大文件上传","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/业务场景/超大文件上传/大文件上传.md","filePath":"generated-notes/前端/业务场景/超大文件上传/大文件上传.md"}'),o={name:"generated-notes/前端/业务场景/超大文件上传/大文件上传.md"};function r(s,e,c,n,h,d){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="大文件上传" tabindex="-1">大文件上传 <a class="header-anchor" href="#大文件上传" aria-label="Permalink to &quot;大文件上传&quot;">​</a></h1><h2 id="_1-实现思路" tabindex="-1">1 实现思路 <a class="header-anchor" href="#_1-实现思路" aria-label="Permalink to &quot;1 实现思路&quot;">​</a></h2><ul><li>前端上传大文件时使用 Blob.prototype.slice 将文件切片，并发上传多个切片，最后发送一个合并的请求通知服务端合并切片</li><li>服务端接收切片并存储，收到合并请求后使用流将切片合并到最终文件</li><li>前端使用Web Worker来进行高耗时任务。如果让浏览器中JS有大量计算时，会造成 UI 阻塞，出现界面卡顿、掉帧等情况，严重时还会出现页面卡死等情况（其实很容易触发，例如让你计算十万条数据）。</li><li>原生 XMLHttpRequest 的 upload.onprogress 对切片上传进度的监听</li><li>使用 Vue 计算属性根据每个切片的进度算出整个文件的上传进度</li></ul><h2 id="_2-断点续传、秒传" tabindex="-1">2 断点续传、秒传 <a class="header-anchor" href="#_2-断点续传、秒传" aria-label="Permalink to &quot;2 断点续传、秒传&quot;">​</a></h2><ul><li>使用 spark-md5 根据文件内容算出文件 hash</li><li>通过 hash 可以判断服务端是否已经上传该文件，从而直接提示用户上传成功（秒传）</li><li>通过 XMLHttpRequest 的 abort 方法暂停切片的上传</li><li>上传前服务端返回已经上传的切片名，前端跳过这些切片的上传</li></ul><h2 id="_3-oss对象存储服务" tabindex="-1">3 OSS对象存储服务 <a class="header-anchor" href="#_3-oss对象存储服务" aria-label="Permalink to &quot;3 OSS对象存储服务&quot;">​</a></h2><h4 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>首先OSS的英文全称是Object Storage Service, 直译过来就是”对象存储服务“。 严谨的解释是：OSS是一种使用HTTP API存储和检索非结构化数据和元素的数据对象的工具。 要点：</p><ol><li>HTTP API风格</li><li>存储数据</li><li>检索数据</li></ol><p>通俗易懂的说就是：OSS就是通过HTTP restful风格的API进行数据上传，存储和获取的云端数据库服务。你也可以简单的理解成网盘。</p><p>服务供应商： 阿里云，蓝队云，移动云，AWS存储</p><h4 id="oss的相关术语" tabindex="-1">OSS的相关术语 <a class="header-anchor" href="#oss的相关术语" aria-label="Permalink to &quot;OSS的相关术语&quot;">​</a></h4><h4 id="_1-object-对象" tabindex="-1">1. Object 对象 <a class="header-anchor" href="#_1-object-对象" aria-label="Permalink to &quot;1. Object 对象&quot;">​</a></h4><p>Object是OSS服务存储的基本单元。我们也可以称之为OSS的文件。Object通常由Object Meta（对象元信息，描述信息），Data（数据），和Key（文件名/文件标识）组成。Key是存储空间中的唯一标识，类似于数据库中的Primary key。</p><h4 id="_2-bucket-存储空间" tabindex="-1">2. Bucket 存储空间 <a class="header-anchor" href="#_2-bucket-存储空间" aria-label="Permalink to &quot;2. Bucket 存储空间&quot;">​</a></h4><p>Bucket是用户用于存储对象的容器，所有的对象都必须隶属于某个存储空间。</p><h4 id="_3-region-地域" tabindex="-1">3. Region 地域 <a class="header-anchor" href="#_3-region-地域" aria-label="Permalink to &quot;3. Region 地域&quot;">​</a></h4><p>Region表示OSS的数据中心所在的物理位置。地域选项是由供应商提供的，用户通常可以通过不同资费和需求来选择适合自己的地域服务。</p><h4 id="_4-endpoint-访问域名" tabindex="-1">4. Endpoint 访问域名 <a class="header-anchor" href="#_4-endpoint-访问域名" aria-label="Permalink to &quot;4. Endpoint 访问域名&quot;">​</a></h4><p>Endpoint表示OSS对外服务的访问域名（你的网盘地址）。OSS对外的API是符合RESTful请求风格的。另外不同Region下Endpoint会有所不同。具体的Endpoint要看服务供应商的提供。</p><h4 id="_5-accesskey-访问秘钥-ak" tabindex="-1">5. AccessKey 访问秘钥 （AK） <a class="header-anchor" href="#_5-accesskey-访问秘钥-ak" aria-label="Permalink to &quot;5. AccessKey 访问秘钥 （AK）&quot;">​</a></h4><p>AccessKey简称AK，用于访问资源时验证身份。AccessKey通常包括 AccessId 和 AccessKeySecret。OSS通过使用用AccessKey和AccessKeySecret对称加密的方式来校验身份。 AccessId是用户的标识，AccessKeySecret是用于加密的签名，可以理解为私钥。所以AccessKeySecret必须保密处理。</p><h3 id="oss的优点" tabindex="-1">OSS的优点 <a class="header-anchor" href="#oss的优点" aria-label="Permalink to &quot;OSS的优点&quot;">​</a></h3><ol><li>HTTP RESTful 规范的交互，简单明了，并且具有多平台和系统的通用性。</li><li>合理的资源分配，对于静态资源的处理使用OSS可以降低个人服务的资源压力</li><li>集成CDN，对资源进行缓存处理，提升资源访问速度</li><li>资源版本控制，方便资源在意外覆盖时恢复。</li><li>灵活的扩展性，想要更多的服务，给更多的钱。</li><li>对静态资源进行进一步的封装，降低了系统本身体系结构的复杂度，符合分布式服务的设计理念。</li></ol><h3 id="oss的缺点" tabindex="-1">OSS的缺点 <a class="header-anchor" href="#oss的缺点" aria-label="Permalink to &quot;OSS的缺点&quot;">​</a></h3><ol><li>无法像传统数据库一样维护数据库结构。</li><li>存储对象不允许进行片的更改，只能修改整个对象，会有性能问题</li></ol>',26)])])}const _=a(o,[["render",r]]);export{u as __pageData,_ as default};
